import { NavLink } from 'react-router-dom';

function Navbar() {
  const linkClass = ({ isActive }) =>
    `font-manrope text-sm uppercase tracking-[0.05em] font-medium transition-all duration-300 active:scale-[0.98] ${
      isActive
        ? 'text-primary border-b-2 border-primary pb-1'
        : 'text-on-surface-variant hover:text-primary'
    }`;

  return (
    <nav className="fixed top-0 z-50 w-full bg-white/80 backdrop-blur-xl border-b border-outline-variant/30">
      <div className="flex justify-between items-center px-12 py-8 w-full max-w-[1920px] mx-auto">
        <div className="text-2xl font-black tracking-tighter text-on-surface uppercase">
          <NavLink to="/">
            <span style={{ color: 'rgb(15, 23, 42)', letterSpacing: '-1.2px', textTransform: 'none', backgroundColor: 'rgba(255, 255, 255, 0.7)' }}>
              eTiskarna
            </span>
          </NavLink>
        </div>
        <div className="hidden md:flex items-center space-x-12">
          <NavLink to="/katalog" className={linkClass}>Produkty</NavLink>
          <NavLink to="/sluzby" className={linkClass}>Služby</NavLink>
          <NavLink to="/kontakt" className={linkClass}>Kontakt</NavLink>
        </div>
        <NavLink to="/poptavka">
          <button className="bg-primary text-on-primary px-8 py-3 font-bold uppercase text-xs tracking-widest hover:opacity-90 transition-all active:scale-[0.98] duration-300">
            Poptat kalkulaci
          </button>
        </NavLink>
      </div>
    </nav>
  );
}

export default Navbar;
